import { gsap, ScrollTrigger, SplitText, DrawSVGPlugin, GSDevTools } from './init.js';

// Init
let tl = null;

// Utils
// function to make sure any previous animations are killed before applying a new one
function killAnimations(animationClass) {

    if (tl) {
      tl.kill(true);
    }

    gsap.utils.toArray('.' + animationClass).forEach((el) => {
      // Kill any existing tweens on this element
      gsap.killTweensOf(el);

      // Kill any ScrollTrigger instances attached to this element
      ScrollTrigger.getAll().forEach(trigger => {
          if (trigger.trigger === el) {
              trigger.kill(true);
          }
      });

      // Clear inline styles applied by GSAP
      gsap.set(el, { clearProps: 'all' });
  });
}

// function that checks if given class is found, returns warning when not
function checkClassExists(className) {
  const elements = gsap.utils.toArray('.' + className);
  if (!elements.length) {
    console.warn(`No elements found for class: ${className}`);
    return false;
  }
  return true;
}

// 1. fadeIn animation
// This animation fades in elements on scroll down, and fades out on scroll up
function fadeIn(animationClass) {
  // check for class
  if (!checkClassExists(animationClass)) {
    return;
  }

  // kill any previous animations
  killAnimations(animationClass);

  // scroll down
  gsap.utils.toArray('.' + animationClass).forEach((el, i) => {
    gsap.from(el, {
      scrollTrigger: {
        trigger: el,
        start: 'top 80%',
        toggleActions: 'play none none none'
      },
      overwrite: true,
      y: 50,
      opacity: 0,
      duration: 1,
      delay: 0.5
    });
  });

  // scroll up
  gsap.utils.toArray('.' + animationClass).forEach((el, i) => {
    gsap.to(el, {
      scrollTrigger: {
        trigger: el,
        start: 'top 80%',
        toggleActions: 'play none none reverse'
      },
      overwrite: true,
      y: 0,
      opacity: 1,
      duration: 1,
      delay: 0.5
    });
  });
}

// 2. zoomIn animation
// This animation zooms in elements on scroll down, and zooms out on scroll up
function zoomIn(animationClass) {
  // check for class
  if (!checkClassExists(animationClass)) {
    return;
  }

  // kill any previous animations
  killAnimations(animationClass);

  // scroll down
  gsap.utils.toArray('.' + animationClass).forEach((el, i) => {
    gsap.from(el, {
      scrollTrigger: {
        trigger: el,
        start: 'top 80%',
        toggleActions: 'play none none none'
      },
      overwrite: true,
      scale: 0.5,
      opacity: 0,
      duration: 1,
      delay: 0.5
    });
  });

  // scroll up
  gsap.utils.toArray('.' + animationClass).forEach((el, i) => {
    gsap.to(el, {
      scrollTrigger: {
        trigger: el,
        start: 'top 80%',
        toggleActions: 'play none none reverse'
      },
      overwrite: true,
      scale: 1,
      opacity: 1,
      duration: 1,
      delay: 0.5
    });
  });
}

// 3. slideIn animation
function slideIn(animationClass) {
  // check for class
  if (!checkClassExists(animationClass)) {
    return;
  }

  // Kill any previous animations
  killAnimations(animationClass);

  gsap.utils.toArray('.' + animationClass).forEach((el, i) => {
    gsap.from(el, {
      scrollTrigger: {
        trigger: el,
        start: 'top 80%',
        toggleActions: 'play none none none'
      },
      overwrite: true,
      x: -100,
      opacity: 0,
      duration: 1,
      delay: 0.5
    });
  });

  gsap.utils.toArray('.' + animationClass).forEach((el, i) => {
    gsap.to(el, {
      scrollTrigger: {
        trigger: el,
        start: 'top 80%',
        toggleActions: 'play none none reverse'
      },
      overwrite: true,
      x: 0,
      opacity: 1,
      duration: 1,
      delay: 0.5
    });
  });

}

// 4. stack animation
// Display elements as stack
function stack(animationClass) {
  // check for class
  if (!checkClassExists(animationClass)) {
    return;
  }

  // Kill previous animations
  killAnimations(animationClass);

  tl = gsap.timeline({
    scrollTrigger: {
      trigger: '.gsapy-animations',
      pin: '.gsapy-wrapper',
      start: 'top top',
      end: 'bottom top',
      scrub: 1,
      ease: 'none'
    }
  }).to('.' + animationClass, {
    height: 0,
    paddingBottom: 0,
    opacity: 0,
    stagger: 0.5
  });
}

// 5. Stagger text using splittext
function waveText(animationClass) {
  // check for class
  if (!checkClassExists(animationClass)) {
    return;
  }

  // Kill previous animations
  killAnimations(animationClass);

  SplitText.create('.' + animationClass, {
    type: "words, chars",
    onSplit(self) { // runs every time it splits
      gsap.from(self.chars, {
        duration: 0.5,
        opacity: 0,
        scale: 0,
        y: 80,
        rotationX: 150,
        transformOrigin: "0% 50% -50",
        ease: "back",
        stagger: 0.01,
      });
    }
  });

}

// 6. FadeIn text using splittext
function fadeInText(animationClass) {
  // check for class
  if (!checkClassExists(animationClass)) {
    return;
  }

  // Kill previous animations
  killAnimations(animationClass);

  SplitText.create('.' + animationClass, {
    type: "words",
    onSplit(self) { // runs every time it splits
      gsap.from(self.words, {
        opacity: 0,
        duration: 2,
        ease: "sine.out",
        stagger: 0.01
      });
    }
  });

}

// 7. Flipping characters into place with splittext
// TODO: might need to add perspective to parent element
function flipInText(animationClass) {
  // check for class
  if (!checkClassExists(animationClass)) {
    return;
  }

  // Kill previous animations
  killAnimations(animationClass);

  SplitText.create('.' + animationClass, {
    type: "words",
    onSplit(self) { // runs every time it splits
      gsap.from(self.words, {
        opacity: 0,
        rotationX: 120, // flipping effect
        transformOrigin: "center center",
        duration: 0.8,
        stagger: 0.01,
        ease: "back.out(1.7)" // computationally expensive?
      });
    }
  });

}

// 8. Draw SVG animation
// This animation adds stroke to SVG elements when there isn't, so it can be drawn
// If there's any fill, this will be animated as well
function drawSVG(animationClass, reset = false) {
  // Check for class
  if (!checkClassExists(animationClass)) {
    return;
  }

  // Kill previous animations
  killAnimations(animationClass);

  // check if there are any image tags
  const images = document.querySelectorAll("img." + animationClass);
  if (images.length > 0) {
    images.forEach((img) => {
      console.warn(`Image with class "${animationClass}" found: ${img.src}. This animation is intended for SVG elements only.`);
    });
  }

  // Get all matching SVGs
  const svgs = document.querySelectorAll("svg." + animationClass);

  // add any divs with animationClass that contain an svg as well
  const divs = document.querySelectorAll("div." + animationClass + " svg");

  // add both in one array
  const allSvgs = [...svgs, ...divs];

 //TODO: this runs for every single element but gathers previous elements as well: double work
  allSvgs.forEach((svg) => {

    // TODO: bit clumsy, but this allows the updateGsapy function to work properly
    // if reset is true, remove data-processed attribute
    if (reset) {
      svg.removeAttribute("data-processed");
    }

    // check if this svg is already processed
    if (svg.getAttribute("data-processed") === "true") {
      return;
    }

    // Select paths and shapes within this SVG only
    const paths = svg.querySelectorAll("path");
    const shapes = svg.querySelectorAll("circle, ellipse");

    // Set stroke and stroke-width
    paths.forEach((path) => {
      let fill = path.getAttribute("fill");
      let fallback = false

      if (!fill && !path.getAttribute("stroke")) {
        const styleAttr = path.getAttribute("style");
        const match = /fill:\s*([^;]+)/.exec(styleAttr);
        fill = match ? match[1] : "#000"; // fallback
        fallback = match ? false : true; // if no fill was found, set fallback to true
      }

      // if there's no stroke, set it to the fill color
      path.setAttribute("stroke", path.getAttribute("stroke") || fill);

      // if there's a stroke-width, use that, otherwise default to 5
      path.setAttribute("stroke-width", path.getAttribute("stroke-width") || "5");

      // store fallback value
      path.setAttribute("data-fallback", fallback);
    });

    // Set initial state
    gsap.set(paths, { drawSVG: "0%", fillOpacity: 0 });
    gsap.set(shapes, { opacity: 0, fillOpacity: 0 });

    // Create a timeline for each SVG to keep it coordinated
    let tl = gsap.timeline();

    // calculate duration based on the number of paths
    const duration = Math.max(1, paths.length * 0.2); // minimum 1 second

    tl.to(paths, {
      duration: duration,
      drawSVG: "100%",
      stagger: 0.2,
      ease: "power1.inOut"
    })
    .to(shapes, {
      opacity: 1,
      fillOpacity: 1,
      duration: 0.5
    })
    .to(paths, {
      fillOpacity: 1,
      duration: 0.5,
      // if fallback was used, remove stroke
       onComplete: () => {
         paths.forEach((path) => {
           if (path.getAttribute("data-fallback") === "true") {
             path.removeAttribute("stroke");
           }
         });
       }
    }, "<+1"); // overlap 1 second

    // Debugging timelines
    // link it to this specific timeline:
    // GSDevTools.create({animation: tl});

    // set SVG to processed (data attribute)
    svg.setAttribute("data-processed", "true");

  });
}

// export functions
export { fadeIn, zoomIn, stack, slideIn, waveText, fadeInText, flipInText, drawSVG };
